// Interface of a voltage sensor with extended monitoring capabilities
type VoltageMonitoringSensor interface {
	numericsensor.NumericSensor

	// Get all events that were observed so far, ordered from
	//
	//	most recent to least recent event.
	//	Note: The response might be limited to a certain number of records.
	GetRecentEvents(ctx context.Context) ([]Event, error)

	// Clear list of observed events.
	ClearRecentEvents(ctx context.Context) error

	// Retrieve the dip/swell thresholds.
	//
	//	@return Set of thresholds
	GetDipSwellThresholds(ctx context.Context) (DipSwellThresholds, error)

	// Change the dip/swell thresholds.
	//
	//	@param thresholds  New set of thresholds
	//
	//	@return 0                        if OK
	//	@return THRESHOLD_OUT_OF_RANGE   if any threshold is out of range
	//	@return THRESHOLD_INVALID        if thresholds don't meet the requirements
	SetDipSwellThresholds(ctx context.Context, thresholds DipSwellThresholds) (int32, error)
}

type EventType int

const (
	DIP EventType = iota
	SWELL
	UNKNOWN
)

type DipSwellThresholds struct {
	DipActive             bool    // true if dip events should be monitored
	DipThreshold          float64 // Dip event threshold
	SwellActive           bool    // true if swell events should be monitored
	SwellThreshold        float64 // Swell event threshold
	DeassertionHysteresis float32 // Deassertion hysteresis
}

// Definition of a voltage fluctuation event observed by this sensor
type Event struct {
	Type      EventType // Type of event
	Timestamp time.Time // Time of event occurrence
	Duration  int32     // Event duration in milliseconds
	// Voltage level observed during the event:
	//   - for dip events: lowest voltage observed
	//   - for swell events: highest voltage observed
	Voltage  float64
	Waveform waveform.Waveform // Waveform of event
}

// Event: A new dip/swell event occurred
type EventOccurredEvent interface {
	event.Event
	Event() Event // Event that was observed
	isEventOccurredEvent()
}

// Event: The list of observed events was cleared
type EventListClearedEvent interface {
	userevent.UserEvent
	isEventListClearedEvent()
}

// Event: Dip/swell thresholds were changed
type DipSwellThresholdsChangedEvent interface {
	userevent.UserEvent
	OldThresholds() DipSwellThresholds
	NewThresholds() DipSwellThresholds
	isDipSwellThresholdsChangedEvent()
}
